 1	import type { Dispatch, FC, SetStateAction } from 'react';
 2	import { calculateCidrNotation } from 'src/modules/Providers/views/details/tabs/Hosts/utils/helpers/calculateCidrNotation';
 3	
 4	import { FormGroupWithHelpText } from '@components/common/FormGroupWithHelpText/FormGroupWithHelpText';
 5	import type { SelectValueType } from '@components/common/utils/types';
 6	import { FilterableSelect } from '@components/FilterableSelect/FilterableSelect';
 7	import type { NetworkAdapters } from '@kubev2v/types';
 8	import { HelperText, HelperTextItem, Text } from '@patternfly/react-core';
 9	import { useForkliftTranslation } from '@utils/i18n';
10	
11	import { getSelectedInventoryHostNetworkTriples } from './utils/getSelectedInventoryHostNetworkTriples';
12	import type { InventoryHostNetworkTriple } from './utils/types';
13	
14	type HostsNetworksSelectProps = {
15	  value: NetworkAdapters;
16	  onChange: Dispatch<SetStateAction<NetworkAdapters | undefined>>;
17	  data: InventoryHostNetworkTriple[];
18	  selectedIds: string[];
19	};
20	
21	const HostsNetworksSelect: FC<HostsNetworksSelectProps> = ({
22	  data,
23	  onChange,
24	  selectedIds,
25	
26	  value,
27	}) => {
28	  const { t } = useForkliftTranslation();
29	
30	  const getNetworkAdapterByLabel = (networkAdapters: NetworkAdapters[], label: string) => {
31	    const selectedAdapter = networkAdapters.find((adapter) => {
32	      const cidr = calculateCidrNotation(adapter?.ipAddress, adapter?.subnetMask);
33	      const adapterLabel = `${adapter.name} - ${cidr}`;
34	      return adapterLabel === label;
35	    });
36	
37	    return selectedAdapter;
38	  };
39	  const selectedInventoryHostPairs = getSelectedInventoryHostNetworkTriples(data, selectedIds);
40	  const [firstInventoryHostPair] = selectedInventoryHostPairs;
41	  const networkOptions = firstInventoryHostPair?.inventory?.networkAdapters?.map((adapter) => {
42	    const cidr = calculateCidrNotation(adapter?.ipAddress, adapter?.subnetMask);
43	
44	    return {
45	      description: `${adapter.linkSpeed} Mbps, MTU: ${adapter.mtu}`,
46	      disabled: false,
47	      key: adapter.name,
48	      label: `${adapter.name} - ${cidr}`,
49	    };
50	  });
51	
52	  const onSelect = (selected: SelectValueType) => {
53	    const selectedAdapter = getNetworkAdapterByLabel(
54	      firstInventoryHostPair?.inventory?.networkAdapters ?? [],
55	      selected.toString(),
56	    );
57	
58	    onChange(selectedAdapter);
59	  };
60	
61	  return (
62	    <FormGroupWithHelpText label="Network" isRequired>
63	      <FilterableSelect
64	        placeholder={t('Select a network')}
65	        aria-label={t('Select a network')}
66	        onSelect={(selected) => {
67	          onSelect(selected);
68	        }}
69	        value={value ? `${value?.name} - ${value?.ipAddress}` : ''}
70	        selectOptions={
71	          networkOptions?.map((option) => ({
72	            children: (
73	              <>
74	                <Text>{option.label}</Text>
75	                {option.description && (
76	                  <HelperText>
77	                    <HelperTextItem variant="indeterminate">{option.description}</HelperTextItem>
78	                  </HelperText>
79	                )}
80	              </>
81	            ),
82	            isDisabled: option.disabled,
83	            itemId: option.label,
84	          })) ?? []
85	        }
86	      />
87	    </FormGroupWithHelpText>
88	  );
89	};
90	
91	export default HostsNetworksSelect;

